"use client";
import { useRouter } from "next/navigation";

export default function Navbar() {
  const router = useRouter();

  return (
    <nav className="flex justify-between items-center px-6 py-4 shadow sticky top-0 bg-white z-50">
      
      {/* Logo */}
      <h1
        onClick={() => router.push("/")}
        className="text-xl font-bold text-blue-600 cursor-pointer"
      >
        Quizaro
      </h1>

      {/* Menu */}
      <div className="flex gap-6 items-center">
        <span onClick={() => router.push("/")} className="cursor-pointer">Home</span>
        <span onClick={() => router.push("/tests")} className="cursor-pointer">Tests</span>
        <span onClick={() => router.push("/about")} className="cursor-pointer">About</span>
        <span onClick={() => router.push("/contact")} className="cursor-pointer">Contact</span>

        {/* Admin button (same style as Register) */}
        <button
          onClick={() => router.push("/admin-dashboard")}
          className="bg-blue-500 text-white px-4 py-2 rounded"
        >
          Admin
        </button>

        <button
          onClick={() => router.push("/login")}
          className="border px-4 py-2 rounded"
        >
          Login
        </button>

        <button
          onClick={() => router.push("/register")}
          className="bg-blue-500 text-white px-4 py-2 rounded"
        >
          Register
        </button>
      </div>
    </nav>
  );
}